// src/context/PlayerIdentityContext.js
// ─────────────────────────────────────────────────────────────
// Provides the identity of the currently logged-in player
// (or null if not yet identified).
// ─────────────────────────────────────────────────────────────

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { fetchPlayerByToken } from '../lib/db';
import { getStoredToken, storeToken, clearToken } from '../lib/session';

const PlayerIdentityContext = createContext();

export function PlayerIdentityProvider({ leagueId, children }) {
  const [currentPlayer, setCurrentPlayer] = useState(null);
  const [loading, setLoading]             = useState(true);

  // On mount: check if there's already a stored token for this league
  useEffect(() => {
    if (!leagueId) { setLoading(false); return; }
    const stored = getStoredToken(leagueId);
    if (!stored) { setLoading(false); return; }

    fetchPlayerByToken(stored)
      .then((player) => {
        if (player && player.leagueId === leagueId) {
          setCurrentPlayer(player);
        } else {
          // Token no longer valid (player removed etc.) — clear it
          clearToken(leagueId);
        }
      })
      .catch(() => clearToken(leagueId))
      .finally(() => setLoading(false));
  }, [leagueId]);

  // Called from the PlayerPicker screen
  const loginWithToken = useCallback(async (token) => {
    const player = await fetchPlayerByToken(token.trim());
    if (!player || player.leagueId !== leagueId) {
      throw new Error('Token not found. Check the code and try again.');
    }
    storeToken(leagueId, token.trim());
    setCurrentPlayer(player);
    return player;
  }, [leagueId]);

  const logout = useCallback(() => {
    clearToken(leagueId);
    setCurrentPlayer(null);
  }, [leagueId]);

  const isAdmin = currentPlayer?.role === 'admin';

  return (
    <PlayerIdentityContext.Provider value={{ currentPlayer, loading, loginWithToken, logout, isAdmin }}>
      {children}
    </PlayerIdentityContext.Provider>
  );
}

export function usePlayerIdentity() {
  return useContext(PlayerIdentityContext);
}
